const Card = ({ title, value, icon, color, colSpan, className }) => {
  let colClass = "";
  if (colSpan === "full") colClass = "md:col-span-3";
  else if (colSpan) colClass = `md:col-span-${colSpan}`;

  return (
    <div className={`bg-${color}-100 p-4 rounded ${colClass} ${className || ""}`}>
      <div className="flex items-center space-x-3">
        <span className="text-2xl">{icon}</span>
        <div>
          <p className="text-sm font-medium text-gray-700">{title}</p>
          <p className="text-xl font-semibold">{value}</p>
        </div>
      </div>
    </div>
  );
};

export default Card;
